<?phpclass WebUser extends CWebUser{	public static function getRwFunctionList()	{		$session = Yii::app()->session;		$id = $session['system'];		return isset($session['rw_func'][$id]) ? $session['rw_func'][$id] : '';	}	public function getRoFunctionList()	{		$session = Yii::app()->session;		$id = $session['system'];		return isset($session['ro_func'][$id]) ? $session['ro_func'][$id] : '';	}	public function getCntFunctionList()	{		$session = Yii::app()->session;		$id = $session['system'];		return isset($session['cnt_func'][$id]) ? $session['cnt_func'][$id] : '';	}	public function validRWFunction($func_id)	{		$func = $this->getRwFunctionList();		return (strpos($func,$func_id)!==false);	}		public function validFunction($func_id) {		$func = $this->getRwFunctionList().$this->getRoFunctionList().$this->getCntFunctionList();		return (strpos($func,$func_id)!==false);	}		public function validSystem($sys_id) {		$session = Yii::app()->session;		$rw = (!isset($session['rw_func'][$sys_id])) ? false : !empty($session['rw_func'][$sys_id]);		$ro = (!isset($session['ro_func'][$sys_id])) ? false : !empty($session['ro_func'][$sys_id]);		$cn = (!isset($session['cnt_func'][$sys_id])) ? false : !empty($session['cnt_func'][$sys_id]);		return ($rw || $ro || $cn);	}	public function system() {		return Yii::app()->session['system'];	}	public function city() {		return Yii::app()->session['city'];	}		public function city_name() {		return Yii::app()->session['city_name'];	}		public function city_allow() {		return Yii::app()->session['city_allow'];	}		public function user_display_name() {		return Yii::app()->session['disp_name'];	}		public function logon_time() {		return Yii::app()->session['logon_time'];	}		protected function getCity() {		return $this->city();	}		public function email() {		return Yii::app()->session['email'];	}		public function isSingleCity() {		$str = Yii::app()->session['city_allow'];		$items = explode(",",str_replace("'","",$str));		if (($items===false) || empty($items))			return true;		else			return (count($items)<=1);	}		protected function afterLogin($fromCookie)	{		$sesskey = md5(mt_rand());        $systemId = Yii::app()->params['systemHrId'];		$user=User::model()->find('LOWER(username)=?',array($this->name));		$city = City::model()->find('code=?',array($user->city));		$city_allow = City::model()->getDescendantList($user->city);		$cstr = $user->city;		$city_allow .= (empty($city_allow)) ? "'$cstr'" : ",'$cstr'";				$session = Yii::app()->session;		$this->getUserOption($user);		$access = $user->accessRights();		if (!empty($access)) {		    if($this->validateReviewLongTime($this->name)){                $session['ro_func'] = $access['read_only'];                $session['rw_func'] = $access['read_write'];                $session['cnt_func'] = $access['control'];            }else{ //有待評核員工時僅考核權限                $session['review_ok'] = $access;//考核完成後用於替換掉權限                $session['ro_func'] = array();                $session['rw_func'] = array($systemId=>"RE02");                $session['cnt_func'] = array();            }		} else {			$session['ro_func'] = array();			$session['rw_func'] = array();			$session['cnt_func'] = array();		}		$session['city'] = $user->city;		$session['city_name'] = $city->name;		$session['city_allow'] = $city_allow;		$session['email'] = $user->email;		$session['session_key'] = $sesskey;		$session['session_time'] = date("Y-m-d H:i:s");		$session['disp_name'] = $user->disp_name;		$session['logon_time'] = $user->logon_time;		User::model()->updateByPk($this->id,			array('logon_time'=>new CDbExpression('NOW()'),				'session_key'=>$sesskey,				'fail_count'=>0,			)		);				$this->writeLoginLog();	}    //考核完成後替換成原有的權限	public function reviewFinish(){        $session = Yii::app()->session;        if (isset($session['review_ok']) && !empty($session['review_ok'])) {            $access = $session["review_ok"];            $session['ro_func'] = $access['read_only'];            $session['rw_func'] = $access['read_write'];            $session['cnt_func'] = $access['control'];            unset($session["review_ok"]);        }    }	protected function writeLoginLog() {		$loginlog = new LoginLog;		$loginlog->station_id = isset(Yii::app()->session['station']) ? Yii::app()->session['station'] : 'N/A';		$loginlog->username = $this->name;		$loginlog->client_ip = Yii::app()->request->userHostAddress;		$loginlog->save();	}		protected function beforeLogout() {		User::model()->updateByPk($this->id,array('logoff_time'=>new CDbExpression('NOW()'),'session_key'=>''));		return true;	}	protected function getUserOption($user) {		$options = $user->getUserOption();		if (!empty($options)) {			$session = Yii::app()->session;			foreach ($options as $key=>$value) {				switch ($key) {					case 'lang':						$session['lang'] = $value;						Yii::app()->language = $value;						break;					case 'system':						$session['system'] = $value;						break;				}			}		}	}		public function saveUserOption($name, $key, $value) {		User::model()->saveUserOption($name, $key, $value);	}	private function getFullUrl($base, $path) {		$pos = strpos($path, '/', 1);		$tmp = substr($path, $pos);		return $base.$tmp;	}		public function setUrlAfterLogin() {		$systems = General::systemMapping();		$baseUrl = Yii::app()->getBaseUrl(true);		$returnUrl = $this->getFullUrl($baseUrl, $this->returnUrl);				$session = Yii::app()->session;		if (isset($session['system'])) {			if (strpos($returnUrl,$systems[$session['system']]['webroot'])===false) {				$found = '';				foreach ($systems as $key=>$value) {					if (strpos($returnUrl,$value['webroot'])!==false) {						$found = $key;					}					if (($returnUrl == $value['webroot']) 						|| ($returnUrl == $value['webroot'].'/index.php')) 					{						$this->returnUrl = $systems[$session['system']]['webroot'];						$found = '';						break;					}				}				if ($found!='') $session['system'] = $found;			}		} else {			$session['system'] = Yii::app()->params['systemId'];		}	}    /**     * 驗證管理員是否有未考核的員工.     * @param string $uid 需要被驗證的管理員..     * @return bool true(無未考核員工)  false(有未考核員工).     */    public function validateReviewLongTime($uid=''){        if(empty($uid)){            $uid = Yii::app()->user->id;        }        $suffix = Yii::app()->params['envSuffix'];        $row = Yii::app()->db->createCommand()->select("b.id")->from("hr$suffix.hr_binding a")            ->leftJoin("hr$suffix.hr_employee b","a.employee_id=b.id")            ->leftJoin("security$suffix.sec_user_access e","a.user_id=e.username")            ->where("a.user_id=:user_id and a_read_write like'%RE02%'",array(":user_id"=>$uid))->queryRow();        if($row){ //賬號有綁定的員工且有考核權限            $year = date("Y");            $day = date("m-d");            if($day>="11-01"){                $dateSql = " and ((b.year<=".($year-1).") or (b.year = $year and year_type = 1))";            }elseif ($day>="05-01"){                $dateSql = " and b.year<=".($year-1);            }else{                $dateSql = " and ((b.year<=".($year-2).") or (b.year = ".($year-1)." and year_type = 1))";            }            $count = Yii::app()->db->createCommand()->select("a.id")->from("hr$suffix.hr_review_h a")                ->leftJoin("hr$suffix.hr_review b","a.review_id=b.id")                ->where("a.status_type!=3 and a.handle_id=:handle_id $dateSql",                    array(":handle_id"=>$row['id'])                )->queryRow();            if($count){ //存在未考核的員工                return false;            }        }        return true;    }}